<template>
  <div class="code-exec-tool">
    <el-card>
      <div slot="header">
        <span>代码执行器</span>
        <el-tag v-if="backendAvailable" type="success" size="small" style="margin-left: 10px">后端可用</el-tag>
        <el-tag v-else type="danger" size="small" style="margin-left: 10px">后端不可用</el-tag>
      </div>

      <el-row :gutter="20">
        <el-col :span="12">
          <div class="section-header">
            <span>代码输入</span>
            <el-select v-model="language" size="small" style="width: 120px">
              <el-option label="JavaScript" value="javascript" />
              <el-option label="Groovy" value="groovy" disabled />
            </el-select>
          </div>
          <el-input
            v-model="code"
            type="textarea"
            :rows="18"
            placeholder="输入要执行的代码..."
          />
          <div class="code-actions">
            <el-button type="primary" @click="executeCode" :loading="executing" :disabled="!backendAvailable">
              执行代码
            </el-button>
            <el-button @click="loadExample">加载示例</el-button>
            <el-button @click="clear">清空</el-button>
          </div>
        </el-col>

        <el-col :span="12">
          <el-tabs v-model="activeTab">
            <el-tab-pane label="输出结果" name="output">
              <el-input
                v-model="output"
                type="textarea"
                :rows="8"
                readonly
                placeholder="执行结果..."
              />
            </el-tab-pane>
            <el-tab-pane label="标准输出" name="stdout">
              <el-input
                v-model="stdout"
                type="textarea"
                :rows="8"
                readonly
                placeholder="标准输出..."
              />
            </el-tab-pane>
            <el-tab-pane label="错误信息" name="stderr">
              <el-input
                v-model="stderr"
                type="textarea"
                :rows="8"
                readonly
                placeholder="错误信息..."
              />
            </el-tab-pane>
          </el-tabs>

          <el-divider>执行历史</el-divider>
          <div class="history-list">
            <div v-for="(item, index) in history" :key="index" class="history-item" @click="loadHistory(item)">
              <div class="history-code">{{ item.code.substring(0, 50) }}...</div>
              <div class="history-time">{{ item.time }}</div>
            </div>
            <el-empty v-if="history.length === 0" description="暂无历史记录" :image-size="60" />
          </div>
        </el-col>
      </el-row>

      <el-divider>代码示例</el-divider>
      <div class="examples">
        <el-tag v-for="example in examples" :key="example.name" @click="loadCodeExample(example)" style="cursor: pointer; margin: 3px">
          {{ example.name }}
        </el-tag>
      </div>
    </el-card>
  </div>
</template>

<script>
export default {
  name: 'CodeExecTool',
  data() {
    return {
      code: '',
      language: 'javascript',
      output: '',
      stdout: '',
      stderr: '',
      activeTab: 'output',
      executing: false,
      backendAvailable: false,
      history: [],
      examples: [
        { name: 'Hello World', code: 'print("Hello, World!");' },
        { name: '数学计算', code: 'var result = 1 + 2 + 3 + 4 + 5;\nprint("Sum: " + result);' },
        { name: '数组操作', code: 'var arr = [1, 2, 3, 4, 5];\nvar doubled = arr.map(function(x) { return x * 2; });\nprint(doubled);' },
        { name: '对象操作', code: 'var obj = { name: "张三", age: 25 };\nobj.city = "北京";\nprint(JSON.stringify(obj));' },
        { name: '循环示例', code: 'for (var i = 1; i <= 10; i++) {\n  print("第 " + i + " 次循环");\n}' },
        { name: '函数定义', code: 'function factorial(n) {\n  if (n <= 1) return 1;\n  return n * factorial(n - 1);\n}\nprint("5! = " + factorial(5));' }
      ]
    }
  },
  mounted() {
    this.checkBackend()
  },
  methods: {
    async checkBackend() {
      try {
        const response = await fetch('/api/ping')
        this.backendAvailable = response.ok
      } catch (e) {
        this.backendAvailable = false
      }
    },
    async executeCode() {
      if (!this.code.trim()) {
        this.$message.warning('请输入代码')
        return
      }

      this.executing = true
      this.output = ''
      this.stdout = ''
      this.stderr = ''

      try {
        const response = await fetch('/api/code/execute', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            language: this.language,
            code: this.code
          })
        })

        const result = await response.json()

        if (result.success) {
          this.output = result.output || '(无返回值)'
          this.stdout = result.stdout || '(无输出)'
          this.stderr = result.stderr || '(无错误)'
          this.$message.success('执行成功')
        } else {
          this.stderr = result.error
          this.activeTab = 'stderr'
          this.$message.error('执行失败')
        }

        this.history.unshift({
          code: this.code,
          language: this.language,
          time: new Date().toLocaleString(),
          success: result.success
        })

        if (this.history.length > 20) {
          this.history.pop()
        }
      } catch (e) {
        this.stderr = '请求失败: ' + e.message
        this.activeTab = 'stderr'
        this.$message.error('请求失败')
      } finally {
        this.executing = false
      }
    },
    loadExample() {
      this.code = `// JavaScript 代码示例
var message = "Hello, World!";
print(message);

// 数学运算
var sum = 0;
for (var i = 1; i <= 100; i++) {
  sum += i;
}
print("1到100的和: " + sum);`
    },
    loadCodeExample(example) {
      this.code = example.code
    },
    loadHistory(item) {
      this.code = item.code
      this.language = item.language
    },
    clear() {
      this.code = ''
      this.output = ''
      this.stdout = ''
      this.stderr = ''
    }
  }
}
</script>

<style scoped>
.code-exec-tool {
  padding: 20px;
}

.section-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 10px;
}

.code-actions {
  margin-top: 10px;
  text-align: center;
}

.history-list {
  max-height: 200px;
  overflow-y: auto;
}

.history-item {
  padding: 8px;
  background: #f5f7fa;
  border-radius: 4px;
  margin-bottom: 5px;
  cursor: pointer;
  transition: all 0.3s;
}

.history-item:hover {
  background: #e6f7ff;
}

.history-code {
  font-family: monospace;
  font-size: 12px;
  color: #606266;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.history-time {
  font-size: 11px;
  color: #909399;
  margin-top: 3px;
}

.examples {
  display: flex;
  flex-wrap: wrap;
  gap: 5px;
}
</style>
